import React from 'react';
import './App.css';

function App() {
  return (
    <div className="App">
      <h1>Welcome to my React Project!</h1>
    </div>
  );
}

export default App;

import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import App from './App';

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);

import React from 'react';
import './header.css';

function Header() {
  return (
    <header className="header">
      <h1>My React Project</h1>
    </header>
  );
}

export default Header;

import React from 'react';
import './footer.css';

function Footer() {
  return (
    <footer className="footer">
      <p>&copy; 2021 My React Project. All rights reserved.</p>
    </footer>
  );
}

export default Footer;

import React from 'react';
import './main.css';

function Main() {
  return (
    <main className="main">
      <h2>Welcome to the main section!</h2>
      <p>This is the content of the main section in my React project.</p>
    </main>
  );
}

export default Main;

.main {
  background-color: #f2f2f2;
  padding: 20px;
}

.main h2 {
  color: #333;
}

.main p {
  color: #666;
}

.header {
  background-color: #333;
  color: #fff;
  padding: 20px;
}

.header h1 {
  font-size: 24px;
  margin: 0;
}

.footer {
  background-color: #333;
  color: #fff;
  padding: 10px;
  text-align: center;
}

.footer p {
  margin: 0;
}
